.logs-container {
    max-width: 1100px;
    margin: 0 auto;
    padding: 30px 20px;
    background: #ffffff;
    border-radius: 12px;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.05);
}

.logs-title {
    margin-top: 0;
    font-size: 2rem;
    font-weight: bold;
    color: #1e3d59;
    text-align: center;
    margin-bottom: 30px;
}

.logs-controls {
    display: flex;
    flex-wrap: wrap;
    gap: 20px;
    align-items: center;
    justify-content: center;
    margin-bottom: 30px;
}

.logs-controls label {
    font-weight: 600;
    color: #333;
}

.logs-controls input[type="date"],
.logs-controls select {
    padding: 10px 16px;
    border-radius: 8px;
    border: 1px solid #ccc;
    font-size: 1rem;
    background: #f7f7f7;
    transition: all 0.3s ease;
}

.logs-controls input[type="date"]:hover,
.logs-controls select:hover {
    border-color: #888;
    background: #fff;
}

.logs-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 10px;
    border-radius: 10px;
    overflow: hidden;
    box-shadow: 0 4px 20px rgba(0,0,0,0.06);
    background: #fdfdfd;
}

.logs-table th, .logs-table td {
    padding: 14px 16px;
    text-align: left;
}

.logs-table th {
    background: #1e3d59;
    color: #fff;
    text-transform: uppercase;
    font-size: 0.85rem;
}

.logs-table tr:nth-child(even) {
    background: #f3f6f9;
}

.logs-table tr:hover {
    background: #e0f0ff;
    transition: background 0.2s ease;
}

.no-logs {
    text-align: center;
    font-size: 1.1rem;
    margin-top: 40px;
    color: #777;
}

