/* =============================================================
   STITCH DESIGN SYSTEM — "The Immutable Ledger"
   Vanilla CSS implementation of the MD3 tonal palette
   ============================================================= */

/* ─── Design Tokens ─── */
:root {
  /* Tonal palette */
  --primary: #00457b;
  --primary-container: #1f5d99;
  --on-primary: #ffffff;
  --on-primary-container: #b8d5ff;
  --primary-fixed: #d2e4ff;
  --primary-fixed-dim: #a1c9ff;

  --secondary: #15629a;
  --secondary-container: #83c1fe;
  --secondary-fixed: #cfe5ff;
  --secondary-fixed-dim: #99cbff;
  --on-secondary-fixed-variant: #004a78;

  --tertiary: #2f4560;
  --tertiary-container: #475c79;
  --tertiary-fixed: #d3e4ff;
  --tertiary-fixed-dim: #b2c8e9;
  --on-tertiary-fixed-variant: #334863;

  --error: #ba1a1a;
  --error-container: #ffdad6;
  --on-error-container: #93000a;

  --surface: #f6faff;
  --surface-dim: #d6dadf;
  --surface-bright: #f6faff;
  --surface-container-lowest: #ffffff;
  --surface-container-low: #f0f4f9;
  --surface-container: #eaeef3;
  --surface-container-high: #e4e9ed;
  --surface-container-highest: #dfe3e8;
  --surface-variant: #dfe3e8;

  --on-surface: #171c20;
  --on-surface-variant: #424750;
  --on-background: #171c20;
  --background: #f6faff;

  --outline: #727781;
  --outline-variant: #c2c7d1;

  --inverse-surface: #2c3135;
  --inverse-on-surface: #edf1f6;

  /* Sidebar gradient */
  --sidebar-from: #163456;
  --sidebar-to: #1f4b73;

  /* Shadows */
  --shadow-ambient: 0 16px 36px rgba(24, 39, 75, 0.06);
  --shadow-card: 0 12px 26px rgba(22, 52, 86, 0.08);
  --shadow-elevated: 0 20px 45px rgba(17, 24, 39, 0.12);

  /* Radii */
  --radius-sm: 6px;
  --radius-md: 8px;
  --radius-lg: 12px;
  --radius-xl: 14px;
  --radius-2xl: 16px;
  --radius-full: 9999px;

  /* Spacing */
  --sp-1: 4px;
  --sp-2: 8px;
  --sp-3: 12px;
  --sp-4: 16px;
  --sp-5: 20px;
  --sp-6: 24px;
  --sp-8: 32px;
}

/* ─── Reset & Base ─── */
@import url("https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap");

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  background: var(--background);
  color: var(--on-surface);
  font-family: "Inter", "Segoe UI", system-ui, sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  min-height: 100vh;
}

a {
  text-decoration: none;
  color: inherit;
  transition:
    color 0.2s,
    background 0.2s;
}
img {
  max-width: 100%;
}

/* ─── Layout Shell ─── */
.layout {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

.main-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 100vh;
  padding: 0;
}

.content-wrapper {
  flex: 1;
  padding: var(--sp-6) var(--sp-8);
  max-width: 1400px;
  margin: 0 auto;
  width: 100%;
}

/* ─────────────────────────────────────────
   DESKTOP NAVBAR (visible ≥1024px)
   ───────────────────────────────────────── */
.desktop-navbar {
  display: none;
  position: sticky;
  top: 0;
  z-index: 1200;
  background: linear-gradient(135deg, var(--sidebar-from), var(--sidebar-to));
  box-shadow: 0 10px 24px rgba(22, 52, 86, 0.24);
}

@media (min-width: 1024px) {
  .desktop-navbar {
    display: block;
  }
}

.navbar-container {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 64px;
  padding: 0 var(--sp-6);
  max-width: 1600px;
  margin: 0 auto;
  overflow: visible;
}

/* Brand */
.navbar-brand {
  display: flex;
  align-items: center;
  gap: var(--sp-2);
  flex-shrink: 0;
  min-width: 200px;
}

.navbar-logo {
  width: 32px;
  height: 32px;
  padding: 4px;
  background: rgba(255, 255, 255, 0.12);
  border-radius: var(--radius-md);
}

.navbar-title h1 {
  margin: 0;
  font-size: 0.95rem;
  font-weight: 800;
  color: #ffffff;
  line-height: 1.2;
  letter-spacing: -0.01em;
}

.navbar-subtitle {
  display: block;
  color: rgba(219, 232, 244, 0.7);
  font-size: 0.65rem;
